// init.js — Point d'entrée : restauration session et démarrage

/* ── INIT ── */
switchTab('meta');
initFmtBar();

const sessionRestored = loadSession();
if (sessionRestored && blocks.length > 0) {
  /* Différer la restauration après le premier paint : canvas visible immédiatement */
  requestAnimationFrame(() => {
    restoreSessionBlocks();
    refreshBlockFonts();
    updUA();
    updTree();
    announce('Session restaurée (' + blocks.length + ' bloc' + (blocks.length > 1 ? 's' : '') + ').');
  });
} else {
  /* Logo République Française ajouté par défaut. */
  addBlock('img', MAR - 27, MAR - 27);
  const logo = blocks[blocks.length - 1];
  logo.imgData = 'data:image/png;base64,';
  logo.alt = 'République Française';
  logo.w = 160;
  logo.h = 140;
  /* Mettre à jour le DOM après modification des propriétés */
  { const el = document.getElementById('el-' + logo.id); if (el) { el.style.width = logo.w + 'px'; el.style.height = logo.h + 'px'; } const ct = document.getElementById('ct-' + logo.id); if (ct) fillCt(ct, logo); }
  addBlock('img', MAR + 580, MAR - 13);
  const logoFinances = blocks[blocks.length - 1];
  logoFinances.imgData = 'data:image/png;base64,';
  logoFinances.alt = 'Finances Publiques';

  // Dimensions ajustables selon le rendu souhaité
  logoFinances.w = 145;
  logoFinances.h = 126;
  /* Mettre à jour le DOM après modification des propriétés */
  { const el = document.getElementById('el-' + logoFinances.id); if (el) { el.style.width = logoFinances.w + 'px'; el.style.height = logoFinances.h + 'px'; } const ct = document.getElementById('ct-' + logoFinances.id); if (ct) fillCt(ct, logoFinances); }
  addBlock('h1', MAR + 160, MAR);
  addBlock('p', MAR - 15, MAR + 130);

}

/* Différer les passes lourdes (arbre de structure, accessibilité, fonts)
   après le premier paint — le canvas est déjà visible, ces mises à jour
   sont invisibles pour l'utilisateur au démarrage. */
requestAnimationFrame(() => {
  refreshBlockFonts();
  requestAnimationFrame(() => {
    updUA();
    updTree();
  });
});

/* Sauvegarder à chaque édition des méta */
['m-title', 'm-author', 'm-subject', 'm-lang'].forEach(id => {
  const el = document.getElementById(id);
  if (el) el.addEventListener('input', () => saveSession());
});

/* Sauvegarder à chaque frappe dans un contenteditable ou textarea de liste */
document.addEventListener('input', e => {
  if (e.target.isContentEditable || e.target.classList.contains('list-ta')) {
    saveSession();
  }
});